<template>
  <!--强制更新弹窗-->
  <el-dialog
    :close-on-click-modal="false"
    :close-on-press-escape="false"
    :modal="true"
    :show-close="!forceUpdate"
    :visible.sync="visible"
    append-to-body
    title="消息"
    width="80%"
  >
    <div>复制以下链接到浏览器打开,下载最新版本的插件和教程。</div>
    <div style="margin-top: 10px">
      <a @click="handleCopy(lastNewVersion.baiduLink)" style="color: #409eff; text-decoration: underline; cursor: pointer" title="点击复制">
        链接：{{ lastNewVersion.baiduLink }}
      </a>
      <br />
      <a
        @click="handleCopy(lastNewVersion.extractCode)"
        style="color: #409eff; text-decoration: underline; cursor: pointer"
        title="点击复制"
        v-if="lastNewVersion && lastNewVersion.extractCode"
      >
        提取码：{{ lastNewVersion.extractCode }}
      </a>
    </div>
  </el-dialog>
</template>
<script>
import { getLastVersion } from '@/api/versionUpdate';
import { getLatestVersion, getMultiConfig } from '@/api/main';
import { getPluginVersion } from '@/utils/cepspy';
import { copyText, toBoolean } from '@/utils/common';
export default {
  name: 'VersionUpdate',
  data() {
    return {
      visible: false,
      forceUpdate: false,
      currentVersion: '1.1.0',
      lasterVersion: '1.1.0',
      lastNewVersion: {}
    };
  },
  created() {
    this.getConfig();
  },
  methods: {
    getConfig() {
      let params = {
        codeList: ['sys.forcedUpdate']
      };
      // 获取配置信息
      Promise.all([getLatestVersion(), getMultiConfig(params)]).then(([versionInfo, multiConfig]) => {
        this.forceUpdate = toBoolean(multiConfig.data['sys.forcedUpdate']);
        this.lasterVersion = versionInfo.data;
        this.currentVersion = getPluginVersion();
        if (this.lasterVersion !== this.currentVersion) {
          getLastVersion().then((response) => {
            this.lastNewVersion = response.data[0];
            this.visible = true;
          });
        }
      });
    },
    handleCopy(text) {
      if (!text) return;
      const status = copyText(text);
      if (status) {
        this.$message.success('复制成功');
      } else {
        this.$message.error('复制失败');
      }
    }
  }
};
</script>
<style scoped></style>
